.darma-loader-loaders-css-10 {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 6px;
      min-width: 72px;
      min-height: 24px;
    }
    .darma-loader-loaders-css-10 i {
      display: block;
      width: 12px;
      height: 12px;
      border-radius: 50%;
      background: var(--loader-color, #ec4899);
      animation: darma-loader-loaders-css-10-dotPulse 0.7s ease-in-out infinite;
    }
    .darma-loader-loaders-css-10 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loaders-css-10 i:nth-child(2) { animation-delay: 0.12s; }
.darma-loader-loaders-css-10 i:nth-child(3) { animation-delay: 0.24s; }
.darma-loader-loaders-css-10 i:nth-child(4) { animation-delay: 0.36s; }
    @keyframes darma-loader-loaders-css-10-dotPulse { 0%, 80%, 100% { transform: translateY(0) scale(.75); opacity: .45; } 40% { transform: translateY(-8px) scale(1); opacity: 1; } }

